import { type } from "arktype"
import { jsonSchemaToType } from "@ark/json-schema"

// The draft-2020-12 $schema URI
const DRAFT_2020_12 = "https://json-schema.org/draft/2020-12/schema"

/**
 * Export an ArkType `schema` to JSON Schema draft-2020-12.
 * The returned object always contains the `$schema` field.
 */
export function exportJsonSchema(schema: type.Any): object {
  const jsonSchema = schema.toJsonSchema({ dialect: DRAFT_2020_12 })
  // toJsonSchema already adds $schema when dialect is provided (non-null),
  // but ensure it's present regardless
  if (!("$schema" in (jsonSchema as object))) {
    return { $schema: DRAFT_2020_12, ...(jsonSchema as object) }
  }
  return jsonSchema as object
}

/**
 * Round-trip an ArkType schema through JSON Schema:
 *  1. Export to JSON Schema draft-2020-12 via `toJsonSchema()`.
 *  2. Re-parse back into an ArkType `Type` via `@ark/json-schema`.
 *  3. Return the re-parsed Type.
 */
export function roundTrip(schema: type.Any): type.Any {
  const jsonSchema = exportJsonSchema(schema)
  return jsonSchemaToType(jsonSchema) as type.Any
}

import { type } from "arktype"
import { exportJsonSchema, roundTrip } from "./roundTrip.ts"

// Read all of stdin
async function readStdin(): Promise<string> {
  const chunks: Buffer[] = []
  for await (const chunk of process.stdin) {
    chunks.push(chunk as Buffer)
  }
  return Buffer.concat(chunks).toString("utf8")
}

async function main(): Promise<void> {
  const raw = await readStdin()
  const input = JSON.parse(raw) as { schema: unknown; corpus: unknown[] }

  // Build the original ArkType type from the definition
  const original = type.raw(input.schema)

  // Export to JSON Schema and round-trip back to ArkType
  const jsonSchema = exportJsonSchema(original)
  const roundTripped = roundTrip(original)

  // Evaluate each corpus item against both types
  const agreements = input.corpus.map((payload, index) => {
    const originalAccept = original.allows(payload)
    const roundTrippedAccept = roundTripped.allows(payload)
    const agree = originalAccept === roundTrippedAccept
    return { index, originalAccept, roundTrippedAccept, agree }
  })

  const allAgree = agreements.every(a => a.agree)

  const output = {
    jsonSchema,
    agreements,
    allAgree,
  }

  process.stdout.write(JSON.stringify(output, null, 2) + "\n")
  process.exit(allAgree ? 0 : 1)
}

main().catch(err => {
  process.stderr.write(String(err) + "\n")
  process.exit(1)
})

